1	//! Pipeline coordinator: drain audio ringbuffer on an OS thread, run wake/VAD, queue STT jobs,
2	//! and emit stdout JSONL transcript events.
3	//!
4	//! Thread topology (locked):
5	//! - CPAL RT callback: push samples to ringbuf (no alloc/no block)
6	//! - Pipeline thread (OS): drain ringbuf; run wake + VAD segmentation; enqueue utterance jobs
7	//! - STT thread (OS): whisper-rs inference
8	//! - Output thread (OS): write JSONL to stdout (only stdout writer)
9	
10	use anyhow::{Context, Result};
11	use ringbuf::traits::Consumer;
12	use std::sync::{
13	    atomic::{AtomicBool, Ordering},
14	    Arc,
15	};
16	use std::time::{Duration, Instant};
17	use tokio_util::sync::CancellationToken;
18	
19	use ringbuf::HeapCons;
20	use crate::config::{Config, PipelineVerbosity};
21	use crate::pipeline::dispatcher::DispatchOutcome;
22	use crate::pipeline::jsonl::{JsonlVerbosity, JsonlWriter};
23	use crate::stt::{SttResult, SttService};
24	use crate::vad::{VadConfig as SegCfg, VadSegmenter, FRAME_SAMPLES};
25	use crate::wake::WakeWord;
26	
27	/// Messages flowing from the dispatcher thread to the output thread.
28	enum OutputMsg {
29	    Utterance(SttResult),
30	    Dispatched { utterance_id: u64, macro_id: String, score: f32 },
31	    NoMatch { utterance_id: u64, transcript: String },
32	}
33	
34	pub struct PipelineHandles {
35	    pub pipeline: std::thread::JoinHandle<()>,
36	    pub output: std::thread::JoinHandle<()>,
37	    pub stt: Option<SttService>,
38	    pub dispatcher: Arc<crate::pipeline::dispatcher::Dispatcher>,
39	}
40	
41	/// Spawn the pipeline worker threads.
42	///
43	/// CRITICAL: do NOT pass the full `AudioHandle` here — callers must keep the
44	/// `StreamGuard` on the main thread (see `src/audio/mod.rs` for rationale).
45	/// Only the ringbuf `consumer` end should be forwarded into the worker.
46	pub fn spawn_pipeline(
47	    audio_consumer: HeapCons<f32>,
48	    config: Config,
49	    ptt_active: Arc<AtomicBool>,
50	    muted: Arc<AtomicBool>,
51	    macro_tx: std::sync::mpsc::Sender<crate::input::inject::MacroCmd>,
52	    shutdown: CancellationToken,
53	) -> Result<PipelineHandles> {
54	    let listen_window = Duration::from_secs(config.pipeline.listen_window_secs);
55	    // Wake pre-roll: keep a short rolling buffer of audio while idle so the first
56	    // post-wake command doesn't lose its leading syllables.
57	    //
58	    // NOTE: this is separate from VAD's own preroll (which only applies once
59	    // LISTENING is active). This buffer is used to "seed" the VAD segmenter at
60	    // the moment wake triggers.
61	    const WAKE_PREROLL_MS: u64 = 600;
62	    let wake_preroll_frames: usize = WAKE_PREROLL_MS.div_ceil(20) as usize;
63	
64	    // Build VAD config from config file.
65	    let ms_to_frames = |ms: u64| ms.div_ceil(20).max(1) as usize;
66	    let seg_cfg = SegCfg {
67	        start_threshold: config.vad.start_threshold,
68	        stop_threshold: config.vad.stop_threshold,
69	        min_speech_frames: ms_to_frames(config.vad.min_speech_ms),
70	        end_silence_frames: ms_to_frames(config.vad.end_silence_ms),
71	        preroll_frames: config.vad.preroll_ms.div_ceil(20) as usize,
72	        tail_frames: config.vad.tail_ms.div_ceil(20) as usize,
73	        max_utterance_frames: (config.vad.max_utterance_secs as usize) * 50, // 50 frames/sec
74	    };
75	
76	    // Wake mode wants “snappy” commands, not conservative segmentation.
77	    // Override a few knobs inside the wake LISTENING window to reduce end-of-speech
78	    // latency. Keep thresholds same as base VAD config.
79	    //
80	    // Targets:
81	    // - end_silence_ms smaller to cut earlier after last word
82	    // - min_speech_ms smaller to accept short commands
83	    // - tail/preroll smaller (wake pre-roll already handled separately)
84	    // - cap utterance length smaller for wake commands
85	    const WAKE_END_SILENCE_MS: u64 = 150;
86	    const WAKE_MIN_SPEECH_MS: u64 = 60;
87	    const WAKE_VAD_PREROLL_MS: u64 = 80;
88	    const WAKE_VAD_TAIL_MS: u64 = 80;
89	    const WAKE_MAX_UTTERANCE_SECS: usize = 4;
90	    const WAKE_FORCE_FLUSH_MS: u64 = 1200;
91	    let seg_cfg_wake = SegCfg {
92	        start_threshold: seg_cfg.start_threshold,
93	        // End speech sooner in noisy environments (wake commands are short).
94	        stop_threshold: (seg_cfg.start_threshold - 0.05).max(seg_cfg.stop_threshold),
95	        min_speech_frames: ms_to_frames(WAKE_MIN_SPEECH_MS),
96	        end_silence_frames: ms_to_frames(WAKE_END_SILENCE_MS),
97	        preroll_frames: ms_to_frames(WAKE_VAD_PREROLL_MS),
98	        tail_frames: ms_to_frames(WAKE_VAD_TAIL_MS),
99	        max_utterance_frames: WAKE_MAX_UTTERANCE_SECS * 50,
100	    };

